THOUGHT: I'll patch addLocAccess to handle a possible null return from getUnderlyingObjectAggressive by adding a null check, conservatively marking both arg and other memory, then run submit-patch to build and test.

```bash
sed -i '/const Value \*UO = getUnderlyingObjectAggressive/,+13c\  const Value *UO = getUnderlyingObjectAggressive(Loc.Ptr);
  // Handle possible null: be conservative and assume it may touch arg and other memory.
  if (!UO) {
    ME |= MemoryEffects::argMemOnly(MR);
    ME |= MemoryEffects(IRMemLocation::Other, MR);
    return;
  }
  if (isa<AllocaInst>(UO))
    return;
  if (isa<Argument>(UO)) {
    ME |= MemoryEffects::argMemOnly(MR);
    return;
  }

  // If it's not an identified object, it might be an argument.
  if (!isIdentifiedObject(UO))
    ME |= MemoryEffects::argMemOnly(MR);
  ME |= MemoryEffects(IRMemLocation::Other, MR);' llvm/lib/Transforms/IPO/FunctionAttrs.cpp && submit-patch
```

